__kernel void solver_2(
	int workload,
	int xmax,
	__global fp* x,
	__global fp* y,
	__global fp* params,
	__global fp* com,
	__global fp* err,
	__global fp* scale,
	__global fp* yy,
	__global fp* initvalu_temp,
	__global fp* finavalu_temp)
{
	int bx = get_group_id(0);
	int tx = get_local_id(0);
	int tid = bx * NUMBER_THREADS + tx;

	fp err_exponent = 1.0f / 7.0f;
	fp h_init = 1.0f;
	fp h = h_init;
	int xmin = 0;
	fp tolerance = 10.0f / (fp)(xmax - xmin);

	if (xmax < xmin || h <= 0.0f) return;
	if (xmax == xmin) return;
	if (h > (xmax - xmin)) h = (fp)xmax - (fp)xmin;

	if (tid < workload) {
		for (int k = 1; k <= xmax; k++) {
			long y_pointer_initial = tid * ((xmax + 1) * EQUATIONS) + (k - 1) * EQUATIONS;
			long y_pointer_current = tid * ((xmax + 1) * EQUATIONS) + k * EQUATIONS;
			long x_pointer_current = tid * (xmax + 1) + k;

			x[x_pointer_current] = (fp)k;
			h = h_init;

			fp scale_fina = 1.0f;

			for (int j = 0; j < 12; j++) {
				int error = 0;
				int outside = 0;
				fp scale_min = 4.0f;

				embedded_fehlberg_7_8_2(
					h,
					x[x_pointer_current],
					&y[y_pointer_initial],
					&y[y_pointer_current],
					&params[tid * PARAMETERS],
					&err[tid * EQUATIONS],
					&initvalu_temp[tid * EQUATIONS],
					&finavalu_temp[tid * 13 * EQUATIONS],
					&com[tid * 3]);

				for (int i = 0; i < EQUATIONS; i++) {
					if (err[tid * EQUATIONS + i] > 0) {
						error = 1;
					}
				}
				if (error != 1) {
					scale_fina = 4.0f;
					break;
				}

				for (int i = 0; i < EQUATIONS; i++) {
					if (y[y_pointer_initial + i] == 0.0f) {
						yy[tid * EQUATIONS + i] = tolerance;
					} else {
						yy[tid * EQUATIONS + i] = fabs(y[y_pointer_initial + i]);
					}
					scale[tid * EQUATIONS + i] = 0.8f * pow(tolerance * yy[tid * EQUATIONS + i] / err[tid * EQUATIONS + i], err_exponent);
					if (scale[tid * EQUATIONS + i] < scale_min) {
						scale_min = scale[tid * EQUATIONS + i];
					}
				}
				scale_fina = fmin(fmax(scale_min, 0.125f), 4.0f);

				for (int i = 0; i < EQUATIONS; i++) {
					if (err[tid * EQUATIONS + i] > tolerance * yy[tid * EQUATIONS + i]) {
						outside = 1;
					}
				}
				if (outside == 0) {
					break;
				}

				h = h * scale_fina;

				if (h >= 0.9f) h = 0.9f;

				if (x[x_pointer_current] + h > (fp)xmax) {
					h = (fp)xmax - x[x_pointer_current];
				} else if (x[x_pointer_current] + h + 0.5f * h > (fp)xmax) {
					h = 0.5f * h;
				}
			}

			x[x_pointer_current] = x[x_pointer_current] + h;

			if (j >= 12) {
				return;
			}
		}
	}
}

